#!/usr/bin/env bash
# ==============================================================================
#  StreamForge v2 — IPTV Playout Manager with EPG
#  Local media · Plex import · Jellyfin import · FFmpeg playout
#  https://github.com/rpoltera/streamforge
#
#  Run on Proxmox host:
#    bash -c "$(curl -fsSL https://raw.githubusercontent.com/rpoltera/streamforge/refs/heads/main/streamforge.sh)"
# ==============================================================================

set -Eeuo pipefail
trap 'echo -e "\n\033[01;31m[ERROR]\033[m line ${LINENO}: ${BASH_COMMAND}" >&2; exit 1' ERR

YW='\033[33m'; GN='\033[1;92m'; RD='\033[01;31m'
BL='\033[36m'; DGN='\033[32m'; CL='\033[m'
BFR="\\r\\033[K"
CM="${GN}✓${CL}"; CROSS="${RD}✗${CL}"; TAB="  "
msg_info() { local s="$1"; printf "${TAB}${YW}[ .. ]${CL} %s..." "$s"; }
msg_ok()   { local s="$1"; printf "${BFR}${TAB}${CM} %s\n" "$s"; }
msg_error(){ local s="$1"; printf "${BFR}${TAB}${CROSS} %s\n" "$s"; exit 1; }

B64_PREINSTALL=""
B64_PKG=""
B64_IDX=""
B64_HTML=""
B64_CSS=""
B64_JS=""
B64_SETUP=""

APP="StreamForge"; NSAPP="streamforge"
CT_CPU="2"; CT_RAM="1024"; CT_DISK="8"; CT_TAGS="iptv;media;playout"
NEXTID=$(pvesh get /cluster/nextid 2>/dev/null || echo "100")

header_info() {
  clear
  printf '\033[36m'
  cat << 'BANNER'
   _____ __                             ______
  / ___// /_________  ____ _____ ___  / ____/___  _________ ____
  \__ \/ __/ ___/ _ \/ __ `/ __ `__ \/ /_  / __ \/ ___/ __ `/ _ \
 ___/ / /_/ /  /  __/ /_/ / / / / / / __/ / /_/ / /  / /_/ /  __/
/____/\__/_/   \___/\__,_/_/ /_/ /_/_/    \____/_/   \__, /\___/
                                                     /____/
BANNER
  printf '\033[m'
  echo -e "  ${BL}IPTV Playout · Local Media · Plex · Jellyfin · FFmpeg${CL}"
  echo -e "  ${DGN}github.com/rpoltera/streamforge${CL}\n"
}

prompt_settings() {
  echo -e "${YW}Default settings:${CL}"
  echo -e "  CT ID: ${BL}${NEXTID}${CL}  Host: ${BL}${NSAPP}${CL}  CPU: ${BL}${CT_CPU}${CL}  RAM: ${BL}${CT_RAM}MB${CL}  Disk: ${BL}${CT_DISK}GB${CL}  OS: ${BL}Debian 12${CL}\n"
  read -r -p "Use default settings? [Y/n]: " yn
  case "${yn,,}" in
    n|no) advanced_settings ;;
    *) CT_ID=$NEXTID; CT_HN=$NSAPP; CT_BRG="vmbr0"; CT_NET="dhcp"; CT_GATE=""; CT_VLAN="" ;;
  esac
}

advanced_settings() {
  echo -e "\n${BL}Advanced Settings${CL}\n"
  read -r -p "  CT ID       [${NEXTID}]: " i; CT_ID=${i:-$NEXTID}
  read -r -p "  Hostname    [${NSAPP}]: "  i; CT_HN=${i:-$NSAPP}
  read -r -p "  CPU cores   [${CT_CPU}]: " i; CT_CPU=${i:-$CT_CPU}
  read -r -p "  RAM MB      [${CT_RAM}]: " i; CT_RAM=${i:-$CT_RAM}
  read -r -p "  Disk GB     [${CT_DISK}]: " i; CT_DISK=${i:-$CT_DISK}
  read -r -p "  Bridge      [vmbr0]: "       i; CT_BRG=${i:-vmbr0}
  read -r -p "  IP (blank=DHCP): "           i; CT_NET=${i:-dhcp}
  CT_GATE=""
  [[ "${CT_NET}" != "dhcp" ]] && { read -r -p "  Gateway: " i; CT_GATE=${i:-""}; }
  read -r -p "  VLAN (blank=none): "         i; CT_VLAN=${i:-""}
}

check_existing() {
  if pct list 2>/dev/null | grep -qi "${NSAPP}"; then
    echo -e "\n${YW}Existing StreamForge container found.${CL}"
    read -r -p "Update it? [y/N]: " upd
    if [[ "${upd,,}" == "y" ]]; then
      CT_ID=$(pct list 2>/dev/null | grep -i "${NSAPP}" | awk '{print $1}' | head -1)
      push_file "${B64_PKG}"  "/opt/streamforge/server/package.json" "package.json"
      push_file "${B64_IDX}"  "/opt/streamforge/server/index.js"     "index.js"
      push_file "${B64_HTML}" "/opt/streamforge/public/index.html"   "index.html"
      push_file "${B64_CSS}"  "/opt/streamforge/public/css/main.css" "main.css"
      push_file "${B64_JS}"   "/opt/streamforge/public/js/app.js"    "app.js"
      run_in_container "${B64_SETUP}" "Running setup"
      echo -e "\n${GN}Update complete!${CL}\n"; exit 0
    fi
  fi
}

get_template() {
  msg_info "Locating template storage"
  TMPL_STOR=$(pvesm status -content vztmpl 2>/dev/null | awk 'NR>1{print $1;exit}')
  [[ -z "${TMPL_STOR}" ]] && TMPL_STOR="local"
  msg_ok "Storage: ${TMPL_STOR}"
  msg_info "Checking Debian 12 template"
  TEMPLATE=$(pveam list "${TMPL_STOR}" 2>/dev/null | grep "debian-12" | sort -V | tail -1 | awk '{print $1}')
  if [[ -z "${TEMPLATE}" ]]; then
    msg_info "Downloading Debian 12 template"
    pveam update >/dev/null 2>&1
    local DL; DL=$(pveam available --section system 2>/dev/null | grep "debian-12" | sort -V | tail -1 | awk '{print $1}')
    [[ -z "$DL" ]] && msg_error "No Debian 12 template found."
    pveam download "${TMPL_STOR}" "$DL" >/dev/null 2>&1
    TEMPLATE="${TMPL_STOR}:vztmpl/${DL}"
  fi
  msg_ok "Template: ${TEMPLATE}"
}

create_container() {
  msg_info "Locating rootfs storage"
  local ROOTFS; ROOTFS=$(pvesm status -content images 2>/dev/null | awk 'NR>1{print $1;exit}')
  [[ -z "${ROOTFS}" ]] && ROOTFS="local-lvm"
  msg_ok "Rootfs: ${ROOTFS}"
  local NET_STR="name=eth0,bridge=${CT_BRG},ip=${CT_NET}"
  [[ -n "${CT_GATE:-}" ]] && NET_STR+=",gw=${CT_GATE}"
  [[ -n "${CT_VLAN:-}" ]] && NET_STR+=",tag=${CT_VLAN}"
  msg_info "Creating LXC container CT${CT_ID}"
  pct create "${CT_ID}" "${TEMPLATE}"     -arch amd64 -cores "${CT_CPU}" -hostname "${CT_HN:-$NSAPP}"     -memory "${CT_RAM}" -net0 "${NET_STR}" -onboot 1 -ostype debian     -rootfs "${ROOTFS}:${CT_DISK}" -swap 512 -tags "${CT_TAGS}"     -unprivileged 1 -features "nesting=1" >/dev/null 2>&1
  msg_ok "Container CT${CT_ID} created"
  msg_info "Starting container"
  pct start "${CT_ID}" >/dev/null 2>&1; sleep 6
  msg_ok "Container started"
  msg_info "Waiting for network"
  local tries=0
  until pct exec "${CT_ID}" -- ping -c1 -W2 8.8.8.8 &>/dev/null; do
    tries=$((tries+1)); [[ $tries -gt 20 ]] && msg_error "Network timeout."; sleep 2
  done
  msg_ok "Network ready"
}

push_file() {
  local b64="$1" dest="$2" label="$3"
  msg_info "Writing ${label}"
  printf '%s' "${b64}" | pct exec "${CT_ID}" -- bash -c "base64 -d > '${dest}'"
  msg_ok "${label} written"
}

run_in_container() {
  local b64="$1" label="$2"
  msg_info "${label}"
  printf '%s' "${b64}" | pct exec "${CT_ID}" -- bash -c "base64 -d | bash"
  msg_ok "${label} done"
}

set_description() {
  local ip; ip=$(pct exec "${CT_ID}" -- hostname -I 2>/dev/null | awk '{print $1}')
  pct set "${CT_ID}" -description "# StreamForge v2 IPTV Playout

- **Web UI**: http://${ip}
- **M3U**: http://${ip}/iptv.m3u
- **XMLTV EPG**: http://${ip}/xmltv.xml

Supports: Local media · Plex · Jellyfin · FFmpeg playout
[github.com/rpoltera/streamforge](https://github.com/rpoltera/streamforge)" 2>/dev/null || true
}

main() {
  command -v pveversion &>/dev/null || { echo -e "${RD}Must run on Proxmox VE.${CL}"; exit 1; }
  header_info
  check_existing
  prompt_settings
  echo ""
  get_template
  create_container
  echo ""
  run_in_container "${B64_PREINSTALL}" "Installing Node.js 20, nginx, ffmpeg, packages"
  echo ""
  push_file "${B64_PKG}"  "/opt/streamforge/server/package.json" "package.json"
  push_file "${B64_IDX}"  "/opt/streamforge/server/index.js"     "index.js (server + playout engine)"
  push_file "${B64_HTML}" "/opt/streamforge/public/index.html"   "index.html (UI)"
  push_file "${B64_CSS}"  "/opt/streamforge/public/css/main.css" "main.css (styles)"
  push_file "${B64_JS}"   "/opt/streamforge/public/js/app.js"    "app.js (frontend)"
  echo ""
  run_in_container "${B64_SETUP}" "Configuring npm, systemd, nginx, starting services"
  set_description
  local ip; ip=$(pct exec "${CT_ID}" -- hostname -I 2>/dev/null | awk '{print $1}')
  echo ""
  echo -e "${GN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${CL}"
  echo -e "${GN}  StreamForge v2 deployed to CT${CT_ID}!${CL}"
  echo -e "${GN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${CL}"
  echo ""
  echo -e "  ${YW}Web UI:${CL}    ${BL}http://${ip}${CL}"
  echo -e "  ${YW}M3U:${CL}       ${BL}http://${ip}/iptv.m3u${CL}"
  echo -e "  ${YW}XMLTV EPG:${CL} ${BL}http://${ip}/xmltv.xml${CL}"
  echo ""
  echo -e "  ${DGN}Next steps:${CL}"
  echo -e "  1. Open the Web UI and add a Media Library (Local / Plex / Jellyfin)"
  echo -e "  2. Scan the library to import media"
  echo -e "  3. Create a Channel and build a Playout schedule"
  echo -e "  4. Add the M3U + XMLTV URLs to Plex or Jellyfin Live TV"
  echo ""
  echo -e "  ${DGN}Service: pct enter ${CT_ID} → systemctl status streamforge${CL}"
  echo ""
}

main
